import { Command }
  from 'commander';
import { dirname }
  from 'node:path';
import { existsSync }
  from 'node:fs';
import { mkdir, writeFile }
  from 'node:fs/promises';
import { loadEnvelope,
         saveEnvelope }
  from './model/envelope.js';
import { loadPatch }
  from './model/patch.js';
import { Read, read }
  from './commands/read.js';
import { Write, write }
  from './commands/write.js';
import { Remove, remove }
  from './commands/remove.js';

interface MainOptions
{
  envelopePath?: string;
  patchPath?: string;
}

interface NewEnvelope
{
  instruction: string;
  commands: unknown[];
  files: unknown[];
}

export function resolveEnvelopePath(
    envelopePath?: string
  ): string
{
  return envelopePath
    ?? getRequiredEnv(
      'COG_ENVELOPE_PATH');
}

export function resolvePatchPath(
    patchPath?: string
  ): string
{
  return patchPath
    ?? getRequiredEnv(
      'COG_PATCH_PATH');
}

export async function ensureEnvelopeFile(
    envelopePath: string
  ): Promise<void>
{
  if (existsSync(
      envelopePath)) {
    return;
  }

  await mkdir(
    dirname(
      envelopePath),
    { recursive: true });

  const envelope: NewEnvelope =
    { instruction: '',
      commands: [],
      files: [] };

  await writeFile(
    envelopePath,
    `${JSON.stringify(
      envelope,
      null,
      2)}\n`,
    'utf8');
}

export async function run(
    argv = process.argv
  ): Promise<void>
{
  const program =
    new Command();

  program
    .name(
      'cog')
    .allowExcessArguments(
      false)
    .exitOverride()
    .option(
      '--envelope <path>',
      'path to the envelope JSON file')
    .option(
      '--patch <path>',
      'path to the patch JSON file')
    .showHelpAfterError();

  program
    .command(
      'read')
    .argument(
      '<paths...>')
    .description(
      'read files into the envelope')
    .action(
      async (paths: string[]) => {
        const options =
          program.opts<{
            envelope?: string;
          }>();

        await readCmd(
          paths,
          { envelopePath:
              resolveEnvelopePath(
                options.envelope) });
      });

  program
    .command(
      'apply-patch')
    .description(
      'apply the selected patch to the selected envelope')
    .action(
      async () => {
        const options =
          program.opts<{
            envelope?: string;
            patch?: string;
          }>();

        await applyPatch(
          { envelopePath:
              resolveEnvelopePath(
                options.envelope),
            patchPath:
              resolvePatchPath(
                options.patch) });
      });

  program
    .action(
      () => {
        throw new Error(
          'Usage: cog <read|apply-patch> [args...]');
      });

  await program.parseAsync(
    argv);
}

export async function readCmd(
    args: string[],
    options: MainOptions = {}
  ): Promise<void>
{
  if (args.length === 0) {
    throw new Error(
      'Usage: cog read <path> [<path> ...]');
  }

  const envelopePath =
    resolveEnvelopePath(
      options.envelopePath);

  await ensureEnvelopeFile(
    envelopePath);

  const envelope =
    await loadEnvelope(
      envelopePath);

  for (const filePath of args) {
    await read(
      envelope,
      { command: 'read',
        path: filePath });
  }

  await saveEnvelope(
    envelope,
    envelopePath);
}

export async function applyPatch(
    options: MainOptions = {}
  ): Promise<void>
{
  const envelopePath =
    resolveEnvelopePath(
      options.envelopePath);

  const patchPath =
    resolvePatchPath(
      options.patchPath);

  await ensureEnvelopeFile(
    envelopePath);

  const envelope =
    await loadEnvelope(
      envelopePath);

  const patch =
    await loadPatch(
      patchPath);

  for (const command of patch.commands) {
    if (command.command === 'read') {
      await read(
        envelope,
        command as unknown as Read);
    } else if (command.command === 'write') {
      await write(
        envelope,
        command as unknown as Write);
    } else if (command.command === 'remove') {
      await remove(
        envelope,
        command as unknown as Remove);
    } else {
      throw new Error(
        `Unknown patch command ${command.command}`);
    }
  }

  await saveEnvelope(
    envelope,
    envelopePath);
}

export function getRequiredEnv(
    name: string
  ): string
{
  const value =
    process.env[name];

  if (!value) {
    throw new Error(
      `${name} is required`);
  }

  return value;
}

run()
  .catch(
    error => {
      console.error(
        error instanceof Error
          ? error.message
          : String(error));

      process.exitCode = 1;
    });

import assert
  from 'node:assert/strict';
import { readFile, writeFile }
  from 'node:fs/promises';
import { join }
  from 'node:path';
import test
  from 'node:test';
import { ensureEnvelopeFile,
         getRequiredEnv,
         resolveEnvelopePath }
  from './main.js';
import { withTmpDir }
  from './tmp-dir.js';

test(
  'resolveEnvelopePath uses --envelope before COG_ENVELOPE_PATH',
  () => {
    const previous =
      process.env.COG_ENVELOPE_PATH;

    process.env.COG_ENVELOPE_PATH =
      'env-envelope.json';

    try {
      assert.equal(
        resolveEnvelopePath(
          'cli-envelope.json'),
        'cli-envelope.json');
    } finally {
      if (previous === undefined) {
        delete process.env.COG_ENVELOPE_PATH;
      } else {
        process.env.COG_ENVELOPE_PATH =
          previous;
      }
    }
  });

test(
  'resolveEnvelopePath falls back to COG_ENVELOPE_PATH',
  () => {
    const previous =
      process.env.COG_ENVELOPE_PATH;

    process.env.COG_ENVELOPE_PATH =
      'env-envelope.json';

    try {
      assert.equal(
        resolveEnvelopePath(),
        'env-envelope.json');
    } finally {
      if (previous === undefined) {
        delete process.env.COG_ENVELOPE_PATH;
      } else {
        process.env.COG_ENVELOPE_PATH =
          previous;
      }
    }
  });

test(
  'resolveEnvelopePath keeps existing missing-envelope error behavior',
  () => {
    const previous =
      process.env.COG_ENVELOPE_PATH;

    delete process.env.COG_ENVELOPE_PATH;

    try {
      assert.throws(
        () => resolveEnvelopePath(),
        /COG_ENVELOPE_PATH is required/);
    } finally {
      if (previous !== undefined) {
        process.env.COG_ENVELOPE_PATH =
          previous;
      }
    }
  });

test(
  'getRequiredEnv returns configured environment variable',
  () => {
    const previous =
      process.env.COG_TEST_ENV;

    process.env.COG_TEST_ENV =
      'configured';

    try {
      assert.equal(
        getRequiredEnv(
          'COG_TEST_ENV'),
        'configured');
    } finally {
      if (previous === undefined) {
        delete process.env.COG_TEST_ENV;
      } else {
        process.env.COG_TEST_ENV =
          previous;
      }
    }
  });

test(
  'ensureEnvelopeFile creates a missing envelope file',
  async () => {
    await withTmpDir(
      async dir => {
        const envelopePath =
          join(
            dir,
            'nested',
            'envelope.json');

        await ensureEnvelopeFile(
          envelopePath);

        const envelope =
          JSON.parse(
            await readFile(
              envelopePath,
              'utf8'));

        assert.deepEqual(
          envelope,
          { instruction: '',
            commands: [],
            files: [] });
      });
  });

test(
  'ensureEnvelopeFile does not overwrite an existing envelope file',
  async () => {
    await withTmpDir(
      async dir => {
        const envelopePath =
          join(
            dir,
            'envelope.json');

        const existing =
          '{"instruction":"keep","commands":[1],"files":[2]}\n';

        await writeFile(
          envelopePath,
          existing,
          'utf8');

        await ensureEnvelopeFile(
          envelopePath);

        assert.equal(
          await readFile(
            envelopePath,
            'utf8'),
          existing);
      });
  });

import { mkdtemp, rm }
  from 'node:fs/promises';
import { tmpdir }
  from 'node:os';
import { join }
  from 'node:path';

export interface SilentLogger
{
  debug: (...args: unknown[]) => void;
  error: (...args: unknown[]) => void;
  info: (...args: unknown[]) => void;
  log: (...args: unknown[]) => void;
  warn: (...args: unknown[]) => void;
}

export const silentLogger: SilentLogger =
  { debug: () => {},
    error: () => {},
    info: () => {},
    log: () => {},
    warn: () => {} };

export async function makeTmpDir(
    logger: SilentLogger = silentLogger
  ): Promise<string>
{
  logger.debug(
    'creating temporary test directory');

  return await mkdtemp(
    join(
      tmpdir(),
      'cog-test-'));
}

export async function removeTmpDir(
    path: string,
    logger: SilentLogger = silentLogger
  ): Promise<void>
{
  logger.debug(
    'removing temporary test directory',
    path);

  await rm(
    path,
    { recursive: true,
      force: true });
}

export async function withTmpDir<T>(
    callback: (
      path: string,
      logger: SilentLogger
    ) => Promise<T> | T,
    logger: SilentLogger = silentLogger
  ): Promise<T>
{
  const path =
    await makeTmpDir(
      logger);

  try {
    return await callback(
      path,
      logger);
  } finally {
    await removeTmpDir(
      path,
      logger);
  }
}
